_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = (vUv-.5);// * uAspect.xy;

vec2 uv6 = uv1;
float z = 12*(1+rand_preset)*length((abs(uv1.x)-abs(uv1.y)));
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-4,4);
uv1 -= rs/40;

uv6 = .4*cos(uv1*8);
mus = .002/(length(uv6.y+uv6.x));
mus *= (1+roam_cos);

vec3 crisp= texture(sampler_main,uv1*(1-q28/12+.4*z)+.5);

vec3 ret1 = crisp + mus;

ret = (ret1*.99-.025);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

vec2 tmp = vUv;
float dist = 1;
float inten = 1;
float mask = 0;
ret1 = 0;
int anz = 4;
float n = 1;
vUv = multiply(vUv,mat2(_qa));
//vUv +=.3*q1;
while (n <= anz) {
    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2 *= uAspect.yx;
    dist = 1-fract(1.0/anz*n+q30); //evtl sqrt !
    inten =  pow(dist,.3)*(1-dist)*2;
    vec2 uv3 = 2*uv2*dist+.5;
    neu =  GetPixel (uv3);
    blur = GetBlur2 (uv3);
    neu += blur;
    ret1 = ret1*.9+neu*inten;
n++;
    ret1 *= texture(sampler_rand00, vUv*2.5).xyz;
}


ret = ret1 + .5*vec3(0,0,.3)*vRadius ;


  fragColor = ret;
}
